import { AfterViewInit, Component, Input, OnInit, ViewChild } from '@angular/core';
import { Observable, of, ReplaySubject } from 'rxjs';
import { filter } from 'rxjs/operators';
import { Unitmaster } from './interfaces/unitmaster.model';
import { MatTableDataSource } from '@angular/material/table';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { MatDialog } from '@angular/material/dialog';
import { TableColumn } from '../../../../ux/interfaces/table-column.interface';
import { aioTableData, aioTableLabels } from '../../../../static-data/aio-table-data';
import { UnitmasterCreateUpdateComponent } from './unitmaster-create-update/unitmaster-create-update.component';
import { SelectionModel } from '@angular/cdk/collections';
import { fadeInUp400ms } from '../../../../ux/animations/fade-in-up.animation';
import { MAT_FORM_FIELD_DEFAULT_OPTIONS, MatFormFieldDefaultOptions } from '@angular/material/form-field';
import { stagger40ms } from '../../../../ux/animations/stagger.animation';
import { UntypedFormControl } from '@angular/forms';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';
import { MatSelectChange } from '@angular/material/select';
import { UnitmasterService } from './unitmaster.service';
import { Subscription } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';
import { SharedService } from 'src/app/shared/shared.service';

@UntilDestroy()
@Component({
  selector: 'ux-unitmaster',
  templateUrl: './unitmaster.component.html',
  styleUrls: ['./unitmaster.component.scss'],
  animations: [
    fadeInUp400ms,
    stagger40ms
  ],
  providers: [
    {
      provide: MAT_FORM_FIELD_DEFAULT_OPTIONS,
      useValue: {
        appearance: 'standard'
      } as MatFormFieldDefaultOptions
    }
  ]
})
export class UnitmasterComponent implements OnInit, AfterViewInit {
  layoutCtrl = new UntypedFormControl('fullwidth');
  unitmaster: Unitmaster[];

  @Input()
  columns: TableColumn<Unitmaster>[] = [
    { label: 'Checkbox', property: 'checkbox', type: 'checkbox', visible: true },
    { label: 'Unit Code', property: 'unit_code', type: 'text', visible: true, cssClasses: ['font-medium'] },
    { label: 'Unit Name', property: 'unit_name', type: 'text', visible: true, cssClasses: ['font-medium'] },
    { label: 'Status', property: 'status_display', type: 'text', visible: true, cssClasses: ['font-medium'] },
    { label: 'Created By', property: 'created_by_display', type: 'text', visible: true, cssClasses: ['text-secondary', 'font-medium'] },
    { label: 'Created Date', property: 'created_date_display', type: 'text', visible: true, cssClasses: ['text-secondary', 'font-medium'] },
    { label: 'Modified By', property: 'modified_by_display', type: 'text', visible: true, cssClasses: ['text-secondary', 'font-medium'] },
    { label: 'Modified Date', property: 'modified_date_display', type: 'text', visible: true, cssClasses: ['text-secondary', 'font-medium'] },
    { label: 'Actions', property: 'actions', type: 'button', visible: true }
  ];
  pageSize = 10;
  pageSizeOptions: number[] = [5, 10, 20, 50];
  dataSource: MatTableDataSource<Unitmaster> | null;
  selection = new SelectionModel<Unitmaster>(true, []);
  searchCtrl = new UntypedFormControl();

  @ViewChild(MatPaginator, { static: true }) paginator: MatPaginator;
  @ViewChild(MatSort, { static: true }) sort: MatSort;

  unitmaster_list = [];

  constructor(
    private dialog: MatDialog,
    private unitService: UnitmasterService,
    private authService: AuthService,
    private sharedService: SharedService
  ) {
  }

  get visibleColumns() {
    return this.columns.filter(column => column.visible).map(column => column.property);
  }

  subscription: Subscription;
  ngOnInit() {
    this.subscription = this.unitService.unitmasterChanged
      .subscribe(
        (unitmaster: any[]) => {
          this.unitmaster_list = unitmaster;
          this.formatData();
          this.dataSource.data = this.unitmaster_list;
        }
      );
    this.unitmaster_list = this.unitService.getUnitmaster();
    this.dataSource = new MatTableDataSource();

    this.formatData();

    this.unitmaster = this.unitmaster_list;
    this.dataSource.data = this.unitmaster_list;

    this.searchCtrl.valueChanges.pipe(
      untilDestroyed(this)
    ).subscribe(value => this.onFilterChange(value));
  }

  private formatData() {
    this.unitmaster_list.forEach(async (element) => {
      if (element.created_by) {
        element.created_by_display = element.created_by.first_name + ' ' + element.created_by.last_name;
      }
      if (element.modified_by) {
        element.modified_by_display = element.modified_by.first_name + ' ' + element.modified_by.last_name;
      }
      if (element.created_date) {
        element.created_date_display = this.sharedService.getUTCtoCurrentTime(element.created_date, await this.authService.getUserTimeZone(), this.authService.getCompanyDateTimeFormat());
      }
      if (element.modified_date) {
        element.modified_date_display = this.sharedService.getUTCtoCurrentTime(element.modified_date, await this.authService.getUserTimeZone(), this.authService.getCompanyDateTimeFormat());
      }
      element.status_display = element.status === '1' ? 'Active' : 'In-Active';
    });
  }

  ngAfterViewInit() {
    this.dataSource.paginator = this.paginator;
    this.dataSource.sort = this.sort;
  }

  createUnitmaster() {
    this.dialog.open(UnitmasterCreateUpdateComponent, {
      height: '90vh',
      width: '800px',
      maxWidth: '95vw'
    }).afterClosed().subscribe((unitmaster: Unitmaster) => {
      if (unitmaster) {
        //we will build the custom object here
        unitmaster.loggedin_id = this.authService.getLoggedInID();
        this.unitService.saveUnitmaster(unitmaster);
      }
    });
  }

  updateUnitmaster(unitmaster: Unitmaster) {
    this.dialog.open(UnitmasterCreateUpdateComponent, {
      data: unitmaster,
      height: '90vh',
      width: '800px',
      maxWidth: '95vw'
    }).afterClosed().subscribe(updatedUnitmaster => {
      if (updatedUnitmaster) {
        updatedUnitmaster.loggedin_id = this.authService.getLoggedInID();  
        this.unitService.saveUnitmaster(updatedUnitmaster);
      }
    });
  }

  deleteUnitmaster(unitmaster: Unitmaster) {
    this.unitService.deleteGroup(unitmaster._id);
    this.unitmaster.splice(this.unitmaster.findIndex((existingUnitmaster) => existingUnitmaster._id === unitmaster._id), 1);
    this.selection.deselect(unitmaster);
  }

  deleteSupercategories(unitmaster: Unitmaster[]) {
    unitmaster.forEach(c => this.deleteUnitmaster(c));
  }

  onFilterChange(value: string) {
    if (!this.dataSource) {
      return;
    }
    value = value.trim();
    value = value.toLowerCase();
    this.dataSource.filter = value;
  }

  toggleColumnVisibility(column, event) {
    event.stopPropagation();
    event.stopImmediatePropagation();
    column.visible = !column.visible;
  }

  /** Whether the number of selected elements matches the total number of rows. */
  isAllSelected() {
    const numSelected = this.selection.selected.length;
    const numRows = this.dataSource.data.length;
    return numSelected === numRows;
  }

  /** Selects all rows if they are not all selected; otherwise clear selection. */
  masterToggle() {
    this.isAllSelected() ?
      this.selection.clear() :
      this.dataSource.data.forEach(row => this.selection.select(row));
  }

  trackByProperty<T>(index: number, column: TableColumn<T>) {
    return column.property;
  }
}
